# DINE policy: automatically apply CanNotDelete lock to prod resource groups

# Create the policy definition
cat > /tmp/lock-policy.json << 'EOF'
{
  "mode": "All",
  "parameters": {},
  "policyRule": {
    "if": {
      "allOf": [
        { "field": "type", "equals": "Microsoft.Resources/resourceGroups" },
        { "field": "tags['Environment']", "equals": "prod" }
      ]
    },
    "then": {
      "effect": "DeployIfNotExists",
      "details": {
        "type": "Microsoft.Authorization/locks",
        "existenceCondition": {
          "field": "Microsoft.Authorization/locks/level",
          "equals": "CanNotDelete"
        },
        "roleDefinitionIds": [
          "/providers/microsoft.authorization/roleDefinitions/8e3af657-a8ff-443c-a75c-2fe8c4bcb635"
        ],
        "deployment": {
          "properties": {
            "mode": "incremental",
            "template": {
              "$schema": "https://schema.management.azure.com/schemas/2019-04-01/deploymentTemplate.json#",
              "contentVersion": "1.0.0.0",
              "resources": [{
                "type": "Microsoft.Authorization/locks",
                "apiVersion": "2017-04-01",
                "name": "auto-cannotdelete",
                "properties": {
                  "level": "CanNotDelete",
                  "notes": "Auto-applied by Azure Policy for prod resource groups"
                }
              }]
            }
          }
        }
      }
    }
  }
}
EOF

az policy definition create \
  --name 'auto-lock-prod-rgs' \
  --display-name 'Auto-apply CanNotDelete lock to prod resource groups' \
  --management-group mg-corp \
  --rules @/tmp/lock-policy.json

az policy assignment create \
  --name 'auto-lock-prod-rgs' \
  --policy 'auto-lock-prod-rgs' \
  --scope '/providers/Microsoft.Management/managementGroups/mg-corp' \
  --mi-system-assigned \
  --location eastus

# Grant Owner role to the managed identity so it can create locks
MI_PRINCIPAL=$(az policy assignment show \
  --name auto-lock-prod-rgs \
  --scope '/providers/Microsoft.Management/managementGroups/mg-corp' \
  --query identity.principalId -o tsv)

az role assignment create \
  --assignee $MI_PRINCIPAL \
  --role Owner \
  --scope '/providers/Microsoft.Management/managementGroups/mg-corp'

{
  "$schema": "https://schema.management.azure.com/schemas/2019-04-01/deploymentTemplate.json#",
  "contentVersion": "1.0.0.0",
  "resources": [
    {
      "type": "Microsoft.Storage/storageAccounts",
      "apiVersion": "2023-01-01",
      "name": "saprodaudit",
      "location": "[resourceGroup().location]",
      "sku": { "name": "Standard_GRS" },
      "kind": "StorageV2",
      "properties": {}
    },
    {
      "type": "Microsoft.Storage/storageAccounts/providers/locks",
      "apiVersion": "2017-04-01",
      "name": "saprodaudit/Microsoft.Authorization/audit-nodelete",
      "dependsOn": [
        "[resourceId('Microsoft.Storage/storageAccounts', 'saprodaudit')]"
      ],
      "properties": {
        "level": "CanNotDelete",
        "notes": "Audit log retention requirement — do not delete before 7-year retention period"
      }
    }
  ]
}

# PowerShell: bulk apply CanNotDelete locks across multiple subscriptions
# Run in Azure Cloud Shell or Azure Automation Runbook

param(
    [string]$ManagementGroupId = 'mg-corp',
    [string]$LockName          = 'prod-cannotdelete',
    [string]$EnvironmentTag    = 'prod'
)

$ErrorActionPreference = 'Stop'
$appliedCount  = 0
$skippedCount  = 0
$failedCount   = 0

# Get all subscriptions in the management group
$subs = (Get-AzManagementGroupSubscription -GroupId $ManagementGroupId).Id

foreach ($subId in $subs) {
    try {
        Set-AzContext -SubscriptionId $subId | Out-Null
        Write-Host "Processing subscription: $subId"

        $prodRGs = Get-AzResourceGroup | Where-Object {
            $_.Tags -and $_.Tags.Environment -eq $EnvironmentTag
        }

        foreach ($rg in $prodRGs) {
            $existing = Get-AzResourceLock -ResourceGroupName $rg.ResourceGroupName |
                Where-Object { $_.Name -eq $LockName -and $_.Properties.Level -eq 'CanNotDelete' }

            if ($existing) {
                $skippedCount++
                continue
            }

            New-AzResourceLock `
                -LockName $LockName `
                -LockLevel CanNotDelete `
                -ResourceGroupName $rg.ResourceGroupName `
                -Force | Out-Null
            Write-Host "  Applied: $($rg.ResourceGroupName)"
            $appliedCount++
        }
    }
    catch {
        Write-Warning "  Failed on sub $subId : $_"
        $failedCount++
    }
}

Write-Host "Summary: applied=$appliedCount skipped=$skippedCount failed=$failedCount"
